1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  // Rule examples (simple → complex)
6	  it("should return empty for empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell (underpopulation, 0 neighbors)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent live cells (underpopulation, 1 neighbor each)", () => {
13	    expect(nextGeneration([[0, 0], [0, 1]])).toEqual([]);
14	  });
15	  it("should keep a live cell alive when it has 2 or 3 live neighbors (survival)", () => {
16	    // Pattern: ### on top row, .#. on bottom row
17	    // Cell (1,0) is live with 2 live neighbors (0,0) and (2,0) → survives
18	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 2]]);
19	    expect(result).toContainEqual([1, 0]);
20	  });
21	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
22	    // Gen 0: full 3x3 except center is dead
23	    // ###
24	    // .#.   wait - actually:
25	    // ###
26	    // Cells: (0,0),(1,0),(2,0),(1,1),(0,2),(1,2),(2,2)
27	    // Center (1,1) has 6 live neighbors → dies (overpopulation)
28	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]]);
29	    expect(result).not.toContainEqual([1, 1]);
30	  });
31	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
32	    // Gen 0:       Gen 1:
33	    //  ##.          ##.
34	    //  #..    →     ##.
35	    //  ...          ...
36	    // Dead cell (1,1) has exactly 3 live neighbors (0,0),(1,0),(0,1) → becomes alive
37	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
38	    expect(result).toContainEqual([1, 1]);
39	  });
40	
41	  // Pattern examples
42	  it("should keep a block pattern unchanged (still life)", () => {
43	    // Block pattern: 2x2 square is a still life
44	    // Gen 0:       Gen 1:
45	    //  ##           ##
46	    //  ##    →      ##
47	    // All 4 cells have 3 live neighbors → survive
48	    // No dead cell has exactly 3 live neighbors → no births
49	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
50	    expect(result).toHaveLength(4);
51	    expect(result).toEqual(
52	      expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]])
53	    );
54	  });
55	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
56	});
