1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const parseCellKey = (key: string): Cell => {
6	  const [x, y] = key.split(",");
7	  return [Number(x), Number(y)];
8	};
9	
10	const survives = (isAlive: boolean, liveNeighborCount: number): boolean =>
11	  (isAlive && (liveNeighborCount === 2 || liveNeighborCount === 3)) ||
12	  (!isAlive && liveNeighborCount === 3);
13	
14	function countLiveNeighbors(cells: Cell[]): Map<string, number> {
15	  const counts = new Map<string, number>();
16	  for (const [x, y] of cells) {
17	    for (let dx = -1; dx <= 1; dx++) {
18	      for (let dy = -1; dy <= 1; dy++) {
19	        if (dx === 0 && dy === 0) continue;
20	        const key = cellKey([x + dx, y + dy]);
21	        counts.set(key, (counts.get(key) ?? 0) + 1);
22	      }
23	    }
24	  }
25	  return counts;
26	}
27	
28	export function nextGeneration(cells: Cell[]): Cell[] {
29	  const liveSet = new Set(cells.map(cellKey));
30	  const neighborCounts = countLiveNeighbors(cells);
31	
32	  const result: Cell[] = [];
33	  for (const [key, count] of neighborCounts) {
34	    if (survives(liveSet.has(key), count)) {
35	      result.push(parseCellKey(key));
36	    }
37	  }
38	  return result;
39	}
